import{_ as a,o as t,c as i,a2 as s}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 62 ‚Äî Productivity Tips","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/62-productivity-tips.md","filePath":"chapters/62-productivity-tips.md"}'),o={name:"chapters/62-productivity-tips.md"};function r(p,e,n,l,h,c){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="chapter-62-‚Äî-productivity-tips" tabindex="-1">Chapter 62 ‚Äî Productivity Tips <a class="header-anchor" href="#chapter-62-‚Äî-productivity-tips" aria-label="Permalink to &quot;Chapter 62 ‚Äî Productivity Tips&quot;">‚Äã</a></h1><blockquote><p><em>&quot;Small habits that make a big difference.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ‚≠ê‚≠ê‚≠ê Intermediate <strong>Estimated Reading Time:</strong> 15 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">‚Äã</a></h1><p>These tips will help you get the most out of Vim.</p><hr><h1 id="tip-1-use-relative-numbers" tabindex="-1">Tip 1: Use Relative Numbers <a class="header-anchor" href="#tip-1-use-relative-numbers" aria-label="Permalink to &quot;Tip 1: Use Relative Numbers&quot;">‚Äã</a></h1><div class="language-vim vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vim</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> relativenumber</span></span></code></pre></div><p>Knowing you&#39;re 5 lines away lets you type <code>5j</code> instantly.</p><hr><h1 id="tip-2-learn-the-dot-command" tabindex="-1">Tip 2: Learn the Dot Command <a class="header-anchor" href="#tip-2-learn-the-dot-command" aria-label="Permalink to &quot;Tip 2: Learn the Dot Command&quot;">‚Äã</a></h1><p>The dot command (<code>.</code>) repeats the last change.</p><p>Master it to eliminate repetitive work.</p><hr><h1 id="tip-3-use-macros-for-repetitive-tasks" tabindex="-1">Tip 3: Use Macros for Repetitive Tasks <a class="header-anchor" href="#tip-3-use-macros-for-repetitive-tasks" aria-label="Permalink to &quot;Tip 3: Use Macros for Repetitive Tasks&quot;">‚Äã</a></h1><p>Record a macro once.</p><p>Replay it hundreds of times.</p><hr><h1 id="tip-4-use-the-quickfix-list" tabindex="-1">Tip 4: Use the Quickfix List <a class="header-anchor" href="#tip-4-use-the-quickfix-list" aria-label="Permalink to &quot;Tip 4: Use the Quickfix List&quot;">‚Äã</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:copen      ‚Üí   Open quickfix window</span></span>
<span class="line"><span>:cnext      ‚Üí   Next item</span></span>
<span class="line"><span>:cprev      ‚Üí   Previous item</span></span></code></pre></div><p>Useful for compile errors and search results.</p><hr><h1 id="tip-5-remap-caps-lock" tabindex="-1">Tip 5: Remap Caps Lock <a class="header-anchor" href="#tip-5-remap-caps-lock" aria-label="Permalink to &quot;Tip 5: Remap Caps Lock&quot;">‚Äã</a></h1><p>Map Caps Lock to Escape on your OS.</p><p>This makes returning to normal mode much faster.</p><hr><h1 id="tip-6-avoid-the-mouse" tabindex="-1">Tip 6: Avoid the Mouse <a class="header-anchor" href="#tip-6-avoid-the-mouse" aria-label="Permalink to &quot;Tip 6: Avoid the Mouse&quot;">‚Äã</a></h1><p>Force yourself to use keyboard commands.</p><p>It&#39;s slower at first, but much faster in the long run.</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">‚Äã</a></h1><ul><li>Relative numbers speed up navigation.</li><li>The dot command eliminates repetition.</li><li>Macros automate complex tasks.</li><li>Quickfix handles errors and search results.</li><li>Remap Caps Lock to Escape.</li><li>Avoid the mouse to build muscle memory.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">‚Äã</a></h2><ol><li>Enable relative numbers.</li><li>Use the dot command for 5 repetitive edits.</li><li>Remap Caps Lock to Escape.</li><li>Try coding for one hour without touching the mouse.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">‚Äã</a></h2><p><a href="./63-common-mistakes.html"><strong>Chapter 63 ‚Äî Common Mistakes</strong></a></p><p>Avoid these common Vim pitfalls.</p>`,41)])])}const m=a(o,[["render",r]]);export{u as __pageData,m as default};
